import {
  IntegrationFormType,
  IntegrationServices,
  WithIntegrationTFunction,
} from '@domain/integrations';
import { IntegrationFieldValue } from '@state/integrations';
import { IntegrationFormHelper, IntegrationFormLabel } from 'react-i18next';
import * as yup from 'yup';

export type SimpleIntegrationFieldType =
  | 'text'
  | 'password'
  | 'subdomain'
  | 'enabledSwitch'
  | 'checkbox'
  | 'codeEditorJson'
  | 'credentials'
  | 'label'
  | 'description'
  | 'customFieldSelect'
  | 'link';

export type SimpleIntegrationField = {
  bag?: Record<string, string>;
  fieldType: SimpleIntegrationFieldType;
  formHelperLabel?: IntegrationFormHelper;
  isRequired?: boolean;
  labelId?: IntegrationFormLabel;
  name: string;
};

type IntegrationOauthProps = {
  required?: boolean;
};

export type IntegrationFormProps = {
  /**
   * Bag of magic for custom use cases.
   */
  bag?: Record<string, unknown>;

  /**
   * Common properties accepted by the form
   */
  common?: IntegrationCommonProperties[];

  /**
   * Any custom schema properties for the form
   */
  custom?: yup.ObjectShape;

  extraFields?: SimpleIntegrationField[];

  formType?: IntegrationFormType;

  oauth?: IntegrationOauthProps;

  /**
   * The service for which we are dealing with
   */
  serviceKey: IntegrationServices;

  serviceTitle: string;

  values?: Record<string, IntegrationFieldValue>;
} & WithIntegrationTFunction;

export type IntegrationCommonProperties =
  | 'accessToken'
  | 'actionPageId'
  | 'apiKey'
  | 'appPassword'
  | 'campaignId'
  | 'clientId'
  | 'domain'
  | 'donationPagesOnly'
  | 'email'
  | 'excludedActionPageIds'
  | 'excludedCampaignIds'
  | 'listId'
  | 'listIds'
  | 'name'
  | 'url'
  | 'username'
  | 'password'
  | 'refreshToken'
  | 'scopeId'
  | 'securityToken';

export const integrationCommonKeys: IntegrationCommonProperties[] = [
  'donationPagesOnly',
  'listIds',
  'name',
  'scopeId',
];

export const hubspotCustomKeys = [
  'hubspotActionPageName',
  'communicationsConsentEmail',
  'communicationsConsentPhone',
  'recurring',
  'sourceCode',
  'utmCampaign',
  'utmContent',
  'utmMedium',
  'utmSource',
  'utmTerm',
  'transactionId',
];

export const iterableCustomKeys = [
  'customEvent',
  'includeFormattedAmounts',
  'iterableCampaignId',
  'iterableTemplateId',
  'listIds',
];

export const nationBuilderCustomKeys = ['sendCommitmentData', 'sendFundData'];

export type IntegrationCredentialsProperties = Extract<
  IntegrationCommonProperties,
  | 'accessToken'
  | 'apiKey'
  | 'listId'
  | 'username'
  | 'password'
  | 'email'
  | 'url'
  | 'clientId'
  | 'domain'
  | 'appPassword'
  | 'refreshToken'
  | 'securityToken'
>;

type CredentialsMap = { [k in IntegrationCredentialsProperties]: boolean };

// these should be IntegrationCredentialsProperties
// but ended up with weird issues in defining the types
// for separateCredentialsDetailsEvents in integrationCreateUtils
export const credentialsMap: CredentialsMap = {
  accessToken: true,
  apiKey: true,
  appPassword: true,
  clientId: true,
  domain: true,
  email: true,
  listId: true,
  password: true,
  refreshToken: true,
  securityToken: true,
  url: true,
  username: true,
};

export const integrationCredentialsKeys = Object.keys(
  credentialsMap
) as IntegrationCredentialsProperties[];

const commonPropertiesMap = ({ t }: WithIntegrationTFunction) => {
  // can't set this as key prefix because re-using a general T function for integrationDirectory
  const prefix = 'form.validation';

  return new Map<string, yup.AnyObject>([
    ['accessToken', yup.string().required(t(`${prefix}.accessToken`))],
    [
      'actionPageId',
      yup.string().when('$actionPages', {
        is: true,
        then: (s) => s.required(t(`${prefix}.actionPageId`)),
      }),
    ],
    ['apiKey', yup.string().required(t(`${prefix}.apiKey`))],
    [
      'campaignId',
      yup.string().when('$campaigns', {
        is: true,
        then: (s) => s.required(t(`${prefix}.campaignId`)),
      }),
    ],
    ['donationPagesOnly', yup.boolean()],
    ['email', yup.string().email()],
    ['excludedActionPageIds', yup.string()],
    ['excludedCampaignIds', yup.string()],
    ['listId', yup.string().required(t(`${prefix}.listId`))],
    ['listIds', yup.array(yup.string().nullable()).optional()],
    ['name', yup.string().required(t(`${prefix}.name`))],
    [
      'url',
      yup
        .string()
        .url()
        .required(t(`${prefix}.url`)),
    ],
    ['username', yup.string().required(t(`${prefix}.username`))],
    ['password', yup.string().required(t(`${prefix}.password`))],
    ['scopeId', yup.string()],
  ]);
};

export type CommonPropertyDefaultKey = Exclude<
  IntegrationCommonProperties,
  'actionPageId' | 'campaignId'
>;

export const commonPropertiesDefaults: Record<
  CommonPropertyDefaultKey,
  string | string[] | boolean
> = {
  accessToken: '',
  apiKey: '',
  appPassword: '',
  clientId: '',
  domain: '',
  donationPagesOnly: false,
  email: '',
  excludedActionPageIds: '',
  excludedCampaignIds: '',
  listId: '',
  listIds: [],
  name: '',
  password: '',
  refreshToken: '',
  scopeId: '',
  securityToken: '',
  url: '',
  username: '',
};

export const composeIntegrationFormSchema = (
  keys: IntegrationCommonProperties[],
  options: {
    additionalProperties?: yup.ObjectShape;
  } & WithIntegrationTFunction
) => {
  const { additionalProperties, t } = options;
  const schema = keys.reduce(
    (obj, k) => ({
      ...obj,
      [k]: commonPropertiesMap({ t }).get(k),
    }),
    {}
  );

  return yup.object({ ...schema, ...additionalProperties }) as yup.AnyObjectSchema;
};

